import{_ as a,o as n,c as l,a4 as e}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"化学计量详解","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Learn-Detail-001-化学计量详解-20260405.md","filePath":"chemistry/Chem-Learn-Detail-001-化学计量详解-20260405.md"}'),s={name:"chemistry/Chem-Learn-Detail-001-化学计量详解-20260405.md"};function r(o,t,i,p,g,d){return n(),l("div",null,[...t[0]||(t[0]=[e(`<h1 id="化学计量详解" tabindex="-1">化学计量详解 <a class="header-anchor" href="#化学计量详解" aria-label="Permalink to &quot;化学计量详解&quot;">​</a></h1><p><strong>板块1：化学计算的基石</strong></p><blockquote><p>物质的量是高中化学的「硬门槛」，计算不过关，后续全崩。</p></blockquote><hr><h2 id="第一章-物质的量-摩尔" tabindex="-1">第一章：物质的量（摩尔） <a class="header-anchor" href="#第一章-物质的量-摩尔" aria-label="Permalink to &quot;第一章：物质的量（摩尔）&quot;">​</a></h2><h3 id="_1-1-核心概念" tabindex="-1">1.1 核心概念 <a class="header-anchor" href="#_1-1-核心概念" aria-label="Permalink to &quot;1.1 核心概念&quot;">​</a></h3><p><strong>物质的量</strong>是表示含有一定数目粒子的集合体的物理量，单位是<strong>摩尔（mol）</strong>。</p><p><strong>为什么要引入物质的量？</strong></p><ul><li>微观粒子（原子、分子）太小，无法直接计数</li><li>宏观质量可以测量，但与粒子数不直观对应</li><li>物质的量是宏观质量与微观粒子数之间的「桥梁」</li></ul><p><strong>阿伏伽德罗常数</strong>：</p><ul><li>1 mol任何粒子所含的粒子数约为 <strong>6.02×10²³</strong></li><li>符号：Nₐ</li></ul><p><strong>计算公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>n = N/Nₐ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>n：物质的量（mol）</span></span>
<span class="line"><span>N：粒子数目</span></span>
<span class="line"><span>Nₐ：阿伏伽德罗常数（6.02×10²³ mol⁻¹）</span></span></code></pre></div><p><strong>【典型例题1】</strong> 3.01×10²³个水分子是多少摩尔？</p><p><strong>【详解】</strong> n = N/Nₐ = 3.01×10²³ / 6.02×10²³ = <strong>0.5 mol</strong></p><hr><h3 id="_1-2-摩尔质量" tabindex="-1">1.2 摩尔质量 <a class="header-anchor" href="#_1-2-摩尔质量" aria-label="Permalink to &quot;1.2 摩尔质量&quot;">​</a></h3><p><strong>定义</strong>：单位物质的量的物质所具有的质量，单位 <strong>g/mol</strong>。</p><p><strong>规律</strong>：</p><ul><li>数值上等于相对原子质量或相对分子质量</li><li>单位是 g/mol，不是 g</li></ul><p><strong>计算公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>n = m/M</span></span>
<span class="line"><span></span></span>
<span class="line"><span>n：物质的量（mol）</span></span>
<span class="line"><span>m：质量（g）</span></span>
<span class="line"><span>M：摩尔质量（g/mol）</span></span></code></pre></div><p><strong>常见物质的摩尔质量</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">物质</th><th style="text-align:center;">化学式</th><th style="text-align:center;">摩尔质量(g/mol)</th></tr></thead><tbody><tr><td style="text-align:center;">水</td><td style="text-align:center;">H₂O</td><td style="text-align:center;">18</td></tr><tr><td style="text-align:center;">二氧化碳</td><td style="text-align:center;">CO₂</td><td style="text-align:center;">44</td></tr><tr><td style="text-align:center;">氢氧化钠</td><td style="text-align:center;">NaOH</td><td style="text-align:center;">40</td></tr><tr><td style="text-align:center;">硫酸</td><td style="text-align:center;">H₂SO₄</td><td style="text-align:center;">98</td></tr><tr><td style="text-align:center;">氯化钠</td><td style="text-align:center;">NaCl</td><td style="text-align:center;">58.5</td></tr></tbody></table><p><strong>【典型例题2】</strong> 9 g水（H₂O）的物质的量是多少？</p><p><strong>【详解】</strong></p><ul><li>M(H₂O) = 18 g/mol</li><li>n = m/M = 9 g / 18 g/mol = <strong>0.5 mol</strong></li></ul><hr><h3 id="_1-3-气体摩尔体积" tabindex="-1">1.3 气体摩尔体积 <a class="header-anchor" href="#_1-3-气体摩尔体积" aria-label="Permalink to &quot;1.3 气体摩尔体积&quot;">​</a></h3><p><strong>定义</strong>：单位物质的量的气体所占的体积，标准状况下约为 <strong>22.4 L/mol</strong>。</p><p><strong>⚠️ 重要说明（易错点）</strong>：</p><ul><li><strong>标准状况</strong>：0℃（273K），101 kPa</li><li>只适用于<strong>气态</strong>物质</li><li>液态和固态物质不能用 22.4 L/mol</li></ul><p><strong>计算公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>n = V/Vm</span></span>
<span class="line"><span></span></span>
<span class="line"><span>n：物质的量（mol）</span></span>
<span class="line"><span>V：气体体积（L）</span></span>
<span class="line"><span>Vm：气体摩尔体积（标准状况下 22.4 L/mol）</span></span></code></pre></div><p><strong>【典型例题3】</strong> 标准状况下，11.2 L CO₂的物质的量是多少？质量是多少？</p><p><strong>【详解】</strong></p><ul><li>n = V/Vm = 11.2 L / 22.4 L/mol = <strong>0.5 mol</strong></li><li>m = n × M = 0.5 mol × 44 g/mol = <strong>22 g</strong></li></ul><hr><h3 id="_1-4-物质的量浓度" tabindex="-1">1.4 物质的量浓度 <a class="header-anchor" href="#_1-4-物质的量浓度" aria-label="Permalink to &quot;1.4 物质的量浓度&quot;">​</a></h3><p><strong>定义</strong>：单位体积溶液中所含溶质的物质的量，单位 <strong>mol/L</strong>。</p><p><strong>计算公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c = n/V  或  n = cV</span></span>
<span class="line"><span></span></span>
<span class="line"><span>n：溶质的物质的量（mol）</span></span>
<span class="line"><span>c：物质的量浓度（mol/L）</span></span>
<span class="line"><span>V：溶液体积（L）</span></span></code></pre></div><p><strong>⚠️ 重要提醒</strong>：</p><ul><li>V是<strong>溶液体积</strong>，不是溶剂体积</li><li>单位换算：1 L = 1000 mL</li></ul><p><strong>【典型例题4】</strong> 配制 500 mL 0.1 mol/L NaOH溶液，需要NaOH多少克？</p><p><strong>【详解】</strong></p><ul><li>V = 0.5 L</li><li>n = cV = 0.1 mol/L × 0.5 L = 0.05 mol</li><li>m = nM = 0.05 mol × 40 g/mol = <strong>2 g</strong></li></ul><hr><h2 id="第二章-化学计量综合计算" tabindex="-1">第二章：化学计量综合计算 <a class="header-anchor" href="#第二章-化学计量综合计算" aria-label="Permalink to &quot;第二章：化学计量综合计算&quot;">​</a></h2><h3 id="_2-1-「桥梁」公式总结" tabindex="-1">2.1 「桥梁」公式总结 <a class="header-anchor" href="#_2-1-「桥梁」公式总结" aria-label="Permalink to &quot;2.1 「桥梁」公式总结&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    n（物质的量）</span></span>
<span class="line"><span>                   ↗    ↓    ↘</span></span>
<span class="line"><span>              N/Nₐ     cV     m/M</span></span>
<span class="line"><span>                 ↓      ↓       ↓</span></span>
<span class="line"><span>              粒子数  浓度×体积  质量/摩尔质量</span></span>
<span class="line"><span>                      （气：V/Vm）</span></span></code></pre></div><p><strong>核心思想</strong>：</p><ul><li>无论已知什么条件，<strong>先转化为 n</strong></li><li>再根据化学方程式进行计算</li><li>最后转化为要求的物理量</li></ul><hr><h3 id="_2-2-标准解题步骤" tabindex="-1">2.2 标准解题步骤 <a class="header-anchor" href="#_2-2-标准解题步骤" aria-label="Permalink to &quot;2.2 标准解题步骤&quot;">​</a></h3><p><strong>Step 1：找出已知条件</strong></p><ul><li>已知质量 → 用 n = m/M</li><li>已知气体体积（标况）→ 用 n = V/Vm</li><li>已知浓度和体积 → 用 n = cV</li></ul><p><strong>Step 2：转化为物质的量 n</strong></p><p><strong>Step 3：根据化学方程式计算</strong></p><ul><li>利用化学计量数之比 = 物质的量之比</li></ul><p><strong>Step 4：转化为要求的物理量</strong></p><hr><h3 id="_2-3-典型例题" tabindex="-1">2.3 典型例题 <a class="header-anchor" href="#_2-3-典型例题" aria-label="Permalink to &quot;2.3 典型例题&quot;">​</a></h3><p><strong>【综合例题】</strong> 标准状况下 11.2 L HCl气体溶于水配成 500 mL溶液。 (1) 求所得溶液的物质的量浓度。 (2) 取该溶液 100 mL，能与多少克 NaOH完全反应？</p><p><strong>【详解】</strong></p><p><strong>(1) 求浓度</strong></p><ul><li>n(HCl) = V/Vm = 11.2 L / 22.4 L/mol = 0.5 mol</li><li>c = n/V = 0.5 mol / 0.5 L = <strong>1 mol/L</strong></li></ul><p><strong>(2) 求反应的NaOH质量</strong></p><ul><li>取 100 mL溶液，n(HCl) = cV = 1 mol/L × 0.1 L = 0.1 mol</li><li>反应：HCl + NaOH = NaCl + H₂O</li><li>物质的量之比 1:1，n(NaOH) = 0.1 mol</li><li>m(NaOH) = nM = 0.1 mol × 40 g/mol = <strong>4 g</strong></li></ul><hr><h2 id="第三章-易错点警示" tabindex="-1">第三章：易错点警示 <a class="header-anchor" href="#第三章-易错点警示" aria-label="Permalink to &quot;第三章：易错点警示&quot;">​</a></h2><h3 id="⚠️-易错点1-22-4-l-mol的适用条件" tabindex="-1">⚠️ 易错点1：22.4 L/mol的适用条件 <a class="header-anchor" href="#⚠️-易错点1-22-4-l-mol的适用条件" aria-label="Permalink to &quot;⚠️ 易错点1：22.4 L/mol的适用条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">错误说法</th><th style="text-align:left;">错误原因</th><th style="text-align:left;">正确说法</th></tr></thead><tbody><tr><td style="text-align:left;">&quot;1 mol水在标况下体积是22.4 L&quot;</td><td style="text-align:left;">水是液态，不适用</td><td style="text-align:left;">22.4 L/mol只适用于气体</td></tr><tr><td style="text-align:left;">&quot;常温常压下22.4 L氧气是1 mol&quot;</td><td style="text-align:left;">不是标准状况</td><td style="text-align:left;">必须是标况（0℃，101 kPa）</td></tr></tbody></table><h3 id="⚠️-易错点2-单位换算" tabindex="-1">⚠️ 易错点2：单位换算 <a class="header-anchor" href="#⚠️-易错点2-单位换算" aria-label="Permalink to &quot;⚠️ 易错点2：单位换算&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">易错点</th><th style="text-align:left;">正确做法</th></tr></thead><tbody><tr><td style="text-align:left;">体积用 mL 直接计算</td><td style="text-align:left;">必须先转化为 L：V(L) = V(mL) / 1000</td></tr><tr><td style="text-align:left;">摩尔质量单位写成 g</td><td style="text-align:left;">单位是 g/mol</td></tr></tbody></table><h3 id="⚠️-易错点3-溶液体积-vs-溶剂体积" tabindex="-1">⚠️ 易错点3：溶液体积 vs 溶剂体积 <a class="header-anchor" href="#⚠️-易错点3-溶液体积-vs-溶剂体积" aria-label="Permalink to &quot;⚠️ 易错点3：溶液体积 vs 溶剂体积&quot;">​</a></h3><ul><li>❌ 错误：把溶剂体积当溶液体积</li><li>✅ 正确：题目说「配成 500 mL溶液」，V = 0.5 L</li></ul><hr><h2 id="第四章-配套练习" tabindex="-1">第四章：配套练习 <a class="header-anchor" href="#第四章-配套练习" aria-label="Permalink to &quot;第四章：配套练习&quot;">​</a></h2><h3 id="基础练习" tabindex="-1">基础练习 <a class="header-anchor" href="#基础练习" aria-label="Permalink to &quot;基础练习&quot;">​</a></h3><p><strong>1.</strong> 3.01×10²³个氧分子是多少摩尔？质量是多少克？</p><p><strong>2.</strong> 标准状况下，5.6 L CO₂的质量是多少克？</p><p><strong>3.</strong> 配制 250 mL 0.2 mol/L H₂SO₄溶液，需要H₂SO₄多少克？</p><h3 id="提高练习" tabindex="-1">提高练习 <a class="header-anchor" href="#提高练习" aria-label="Permalink to &quot;提高练习&quot;">​</a></h3><p><strong>4.</strong> 标准状况下，11.2 L某气体的质量为14 g，求该气体的相对分子质量。</p><p><strong>5.</strong> 将 4 g NaOH溶于水配成 500 mL溶液。 (1) 求溶液的物质的量浓度。 (2) 取该溶液 100 mL，加水稀释至 500 mL，求稀释后溶液的浓度。</p><h3 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h3><p><strong>1.</strong> n = 0.5 mol，m = 16 g</p><p><strong>2.</strong> n = 0.25 mol，m = 11 g</p><p><strong>3.</strong> n = 0.05 mol，m = 4.9 g</p><p><strong>4.</strong> n = 0.5 mol，M = 28 g/mol，相对分子质量 = 28</p><p><strong>5.</strong> (1) c = 0.2 mol/L (2) 稀释后 c = 0.04 mol/L</p><hr><h2 id="faq-常见问题" tabindex="-1">FAQ（常见问题） <a class="header-anchor" href="#faq-常见问题" aria-label="Permalink to &quot;FAQ（常见问题）&quot;">​</a></h2><h3 id="q1-物质的量计算时单位总是搞混怎么办" tabindex="-1">Q1：物质的量计算时单位总是搞混怎么办？ <a class="header-anchor" href="#q1-物质的量计算时单位总是搞混怎么办" aria-label="Permalink to &quot;Q1：物质的量计算时单位总是搞混怎么办？&quot;">​</a></h3><p><strong>A</strong>：记住「物质的量 n」是核心：</p><ul><li>n = m/M（质量÷摩尔质量）</li><li>n = V/Vm（气体体积÷22.4 L/mol）</li><li>n = cV（浓度×体积，注意体积单位是L）</li></ul><p><strong>检查方法</strong>：算完后看单位是否合理（n 的单位必须是 mol）。</p><h3 id="q2-不知道该用哪个公式怎么办" tabindex="-1">Q2：不知道该用哪个公式怎么办？ <a class="header-anchor" href="#q2-不知道该用哪个公式怎么办" aria-label="Permalink to &quot;Q2：不知道该用哪个公式怎么办？&quot;">​</a></h3><p><strong>A</strong>：看已知条件：</p><table tabindex="0"><thead><tr><th style="text-align:center;">已知条件</th><th style="text-align:center;">选用公式</th></tr></thead><tbody><tr><td style="text-align:center;">质量和摩尔质量</td><td style="text-align:center;">n = m/M</td></tr><tr><td style="text-align:center;">标况下气体体积</td><td style="text-align:center;">n = V/Vm</td></tr><tr><td style="text-align:center;">浓度和溶液体积</td><td style="text-align:center;">n = cV</td></tr><tr><td style="text-align:center;">粒子数</td><td style="text-align:center;">n = N/Nₐ</td></tr></tbody></table><h3 id="q3-气体摩尔体积什么时候不能用" tabindex="-1">Q3：气体摩尔体积什么时候不能用？ <a class="header-anchor" href="#q3-气体摩尔体积什么时候不能用" aria-label="Permalink to &quot;Q3：气体摩尔体积什么时候不能用？&quot;">​</a></h3><p><strong>A</strong>：以下情况<strong>不能</strong>用 22.4 L/mol：</p><ul><li>物质不是气体（如水、酒精在标况下是液体）</li><li>不是标准状况（常温常压、高温高压等）</li><li>SO₃在标况下是固体</li></ul><hr><p><em>文档编号</em>: Chem-Learn-Detail-001<br><em>板块</em>: 化学计量<br><em>日期</em>: 20260405<br><em>配套文档</em>: Chem-Learn-Method-001（学习方法）、Chem-Supplement-001（纵向跃迁）</p><hr><p><strong>下一板块</strong>：<code>Chem-Learn-Detail-002</code> 元素化学详解（钠、铝、铁、氯、硫、氮）</p>`,108)])])}const m=a(s,[["render",r]]);export{c as __pageData,m as default};
